var surah043 = {
  number: 43,
  nameArabic: "az-Zukhruf",
  nameEnglish: "Az-Zukhruf",
  meaning: "The Ornaments of Gold",
  totalAyahs: 89,
  ayahs: [
    { number: 1, arabic: "حمٓ", transliteration: "Hameem", transliterationB: "Haa-Meeem", english: "Ha-Mim", romanUrdu: "Haa Meem" },
    { number: 2, arabic: "وَٱلْكِتَٰبِ ٱلْمُبِينِ", transliteration: "Waalkitabi almubeeni", transliterationB: "Wal Kitaabil Mubeen", english: "By the Book that makes things clear", romanUrdu: "Kasam hai is wazeh kitaab ki" },
    { number: 3, arabic: "إِنَّا جَعَلْنَٰهُ قُرْءَٰنًا عَرَبِيًّۭا لَّعَلَّكُمْ تَعْقِلُونَ", transliteration: "Inna jaAAalnahu quranan AAarabiyyan laAAallakum taAAqiloona", transliterationB: "Innaa ja'alnaahu Quraanan 'Arabiyyal la'allakum ta'qiloon", english: "We have made it a Qur'an in Arabic, that ye may be able to understand (and learn wisdom)", romanUrdu: "Ke humne isey arabi zubaan ka Quran banaya hai taa-ke tumlog isey samjho" },
    { number: 4, arabic: "وَإِنَّهُۥ فِىٓ أُمِّ ٱلْكِتَٰبِ لَدَيْنَا لَعَلِىٌّ حَكِيمٌ", transliteration: "Wainnahu fee ommi alkitabi ladayna laAAaliyyun hakeemun", transliterationB: "Wa innahoo feee Ummil Kitaabi Ladainaa la'aliyyun hakeem", english: "And verily, it is in the Mother of the Book, in Our Presence, high (in dignity), full of wisdom", romanUrdu: "Aur dar haqeeqat yeh ummul kitaab mein sabt(transcribed) hai, hamare haan badi buland maratba aur hikmat se labrez kitaab" },
    { number: 5, arabic: "أَفَنَضْرِبُ عَنكُمُ ٱلذِّكْرَ صَفْحًا أَن كُنتُمْ قَوْمًۭا مُّسْرِفِينَ", transliteration: "Afanadribu AAankumu alththikra safhan an kuntum qawman musrifeena", transliterationB: "Afanadribu 'ankumuz Zikra safhan an kuntum qawmam musrifeen", english: "Shall We then take away the Message from you and repel (you), for that ye are a people transgressing beyond bounds", romanUrdu: "Ab kya hum tumse bezaar hokar yeh dars-e-naseehat tumhare yahan bhejna chodh dein sirf isliye tum hadd se guzare huey log ho" },
    { number: 6, arabic: "وَكَمْ أَرْسَلْنَا مِن نَّبِىٍّۢ فِى ٱلْأَوَّلِينَ", transliteration: "Wakam arsalna min nabiyyin fee alawwaleena", transliterationB: "Wa kam arsalnaa min Nabiyyin fil awwaleen", english: "But how many were the prophets We sent amongst the peoples of old", romanUrdu: "Pehle guzri hui qaumon mein bhi baarha (baar baar) humne Nabi bheje hain" },
    { number: 7, arabic: "وَمَا يَأْتِيهِم مِّن نَّبِىٍّ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Wama yateehim min nabiyyin illa kanoo bihi yastahzioona", transliterationB: "Wa maa yaateehim min Nabiyyin illaa kaanoo bihee yasahzi'oon", english: "And never came there a prophet to them but they mocked him", romanUrdu: "Kabhi aisa nahin hua ke koi Nabi unke haan (yahan) aaya ho aur unhon ne uska mazak na udaya ho" },
    { number: 8, arabic: "فَأَهْلَكْنَآ أَشَدَّ مِنْهُم بَطْشًۭا وَمَضَىٰ مَثَلُ ٱلْأَوَّلِينَ", transliteration: "Faahlakna ashadda minhum batshan wamada mathalu alawwaleena", transliterationB: "Fa ahlaknaaa ashadda minhum batshanw wa madaa masalul lawwaleen", english: "So We destroyed (them)- stronger in power than these;- and (thus) has passed on the Parable of the peoples of old", romanUrdu: "Phir jo log insey badarja zyada taaqatwar thay unhein humne halak kardiya. Pichli qaumon ki misalien guzar chuki hain" },
    { number: 9, arabic: "وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ خَلَقَهُنَّ ٱلْعَزِيزُ ٱلْعَلِيمُ", transliteration: "Walain saaltahum man khalaqa alssamawati waalarda layaqoolunna khalaqahunna alAAazeezu alAAaleemu", transliterationB: "Wa la'in sa altahum man khalaqas samaawaati wal arda la yaqoolunna khalaqa hunnal 'Azeezul 'Aleem", english: "If thou wert to question them, 'Who created the heavens and the earth?' They would be sure to reply, 'they were created by (Him), the Exalted in Power, Full of Knowledge", romanUrdu: "Agar tum in logon se pucho ke zameen aur aasmaano ko kisne paida kiya hai to yeh khud kahenge ke inhein usi zabardast ilmi hasti ne paida kiya hai" },
    { number: 10, arabic: "ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ مَهْدًۭا وَجَعَلَ لَكُمْ فِيهَا سُبُلًۭا لَّعَلَّكُمْ تَهْتَدُونَ", transliteration: "Allathee jaAAala lakumu alarda mahdan wajaAAala lakum feeha subulan laAAallakum tahtadoona", transliterationB: "Allazee ja'ala lakumul arda mahdanw wa ja'ala lakum feehaa subulal la'allakum tahtadoon", english: "(Yea, the same that) has made for you the earth (like a carpet) spread out, and has made for you roads (and channels) therein, in order that ye may find guidance (on the way)", romanUrdu: "Wahi na jisne tumhare liye is zameen ko gehwara (cradle) banaya aur ismein tumhari khatir raaste bana diye taa-ke tum apni manzil e maqsood ki raah paa sako" },
    { number: 11, arabic: "وَٱلَّذِى نَزَّلَ مِنَ ٱلسَّمَآءِ مَآءًۢ بِقَدَرٍۢ فَأَنشَرْنَا بِهِۦ بَلْدَةًۭ مَّيْتًۭا ۚ كَذَٰلِكَ تُخْرَجُونَ", transliteration: "Waallathee nazzala mina alssamai maan biqadarin faansharna bihi baldatan maytan kathalika tukhrajoona", transliterationB: "Wallazee nazzala minas samaaa'i maaa'am biqadarin fa anshamaa bihee baldatam maitaa' kazaalika tukhrajoon", english: "That sends down (from time to time) rain from the sky in due measure;- and We raise to life therewith a land that is dead; even so will ye be raised (from the dead)", romanUrdu: "Jisne ek khaas miqdar mein aasman se paani utara aur uske zariye se murda (dead) zameen ko jila uthaya. Isi tarah ek roz tum zameen se baramad kiye jaogey" },
    { number: 12, arabic: "وَٱلَّذِى خَلَقَ ٱلْأَزْوَٰجَ كُلَّهَا وَجَعَلَ لَكُم مِّنَ ٱلْفُلْكِ وَٱلْأَنْعَٰمِ مَا تَرْكَبُونَ", transliteration: "Waallathee khalaqa alazwaja kullaha wajaAAala lakum mina alfulki waalanAAami ma tarkaboona", transliterationB: "Wallazee khalaqal azwaaja kullahaa wa ja'ala lakum minal fulki wal-an'aami maa tarkaboon", english: "That has created pairs in all things, and has made for you ships and cattle on which ye ride", romanUrdu: "Wahi jisne yeh tamaam jodey (pairs) paida kiye, aur jisne tumhare liye kashtiyon (ships) aur jaanwaron ko sawari banaya taa-ke tum unki pusht (backs) par chadho" },
    { number: 13, arabic: "لِتَسْتَوُۥا۟ عَلَىٰ ظُهُورِهِۦ ثُمَّ تَذْكُرُوا۟ نِعْمَةَ رَبِّكُمْ إِذَا ٱسْتَوَيْتُمْ عَلَيْهِ وَتَقُولُوا۟ سُبْحَٰنَ ٱلَّذِى سَخَّرَ لَنَا هَٰذَا وَمَا كُنَّا لَهُۥ مُقْرِنِينَ", transliteration: "Litastawoo AAala thuhoorihi thumma tathkuroo niAAmata rabbikum itha istawaytum AAalayhi wataqooloo subhana allathee sakhkhara lana hatha wama kunna lahu muqrineena", transliterationB: "Litastawoo 'alaa zuhoorihee summa tazkuroo ni'mata Rabbikum izastawaitum 'alaihi wa taqooloo Subhaanal lazee sakhkhara lana haaza wa maa kunnaa lahoo muqrineen", english: "In order that ye may sit firm and square on their backs, and when so seated, ye may celebrate the (kind) favour of your Lord, and say, \"Glory to Him Who has subjected these to our (use), for we could never have accomplished this (by ourselves)", romanUrdu: "Aur jab unpar baitho (sit) to apne Rubb ka ehsan yaad karo aur kaho ke “paak hai woh jisne hamare liye in cheezon ko musakkhar(bas mein) kardiya warna hum unhein qaabu mein laane ki taaqat na rakhte thay" },
    { number: 14, arabic: "وَإِنَّآ إِلَىٰ رَبِّنَا لَمُنقَلِبُونَ", transliteration: "Wainna ila rabbina lamunqaliboona", transliterationB: "Wa innaaa ilaa Rabbinaa lamunqaliboon", english: "And to our Lord, surely, must we turn back", romanUrdu: "Aur ek roz humein apne Rubb ki taraf palatna hai”" },
    { number: 15, arabic: "وَجَعَلُوا۟ لَهُۥ مِنْ عِبَادِهِۦ جُزْءًا ۚ إِنَّ ٱلْإِنسَٰنَ لَكَفُورٌۭ مُّبِينٌ", transliteration: "WajaAAaloo lahu min AAibadihi juzan inna alinsana lakafoorun mubeenun", transliterationB: "Wa ja'aloo lahoo min 'ibaadihee juz'aa; innal insaana lakafoorum mubeen", english: "Yet they attribute to some of His servants a share with Him (in his godhead)! truly is man a blasphemous ingrate avowed", romanUrdu: "(Yeh sab kuch jaante aur maante huey bhi) in logon ne uske bandon (servants) mein se baaz ko uska juz (part) bana daala, haqeeqat yeh hai ke Insaan khula ehsan faramosh hai" },
    { number: 16, arabic: "أَمِ ٱتَّخَذَ مِمَّا يَخْلُقُ بَنَاتٍۢ وَأَصْفَىٰكُم بِٱلْبَنِينَ", transliteration: "Ami ittakhatha mimma yakhluqu banatin waasfakum bialbaneena", transliterationB: "Amit takhaza mimmaa yakhluqu banaatinw wa asfaakum bilbaneen", english: "What! has He taken daughters out of what He himself creates, and granted to you sons for choice", romanUrdu: "Kya Allah ne apni makhlooq mein se apne liye betiyan intikhab (chose) ki aur tumhein beiton (sons) se nawaza" },
    { number: 17, arabic: "وَإِذَا بُشِّرَ أَحَدُهُم بِمَا ضَرَبَ لِلرَّحْمَٰنِ مَثَلًۭا ظَلَّ وَجْهُهُۥ مُسْوَدًّۭا وَهُوَ كَظِيمٌ", transliteration: "Waitha bushshira ahaduhum bima daraba lilrrahmani mathalan thalla wajhuhu muswaddan wahuwa katheemun", transliterationB: "Wa izaa bushshira ahaduhum bimaa daraba lir Rahmaani masalan zalla wajhuhoo muswaddanw wa hua kazeem", english: "When news is brought to one of them of (the birth of) what he sets up as a likeness to (Allah) Most Gracious, his face darkens, and he is filled with inward grief", romanUrdu: "Aur haal yeh hai ke jis aulad ko yeh log us khuda e Rehman ki taraf mansoob karte hain uski wiladat ka musda (tidings/news/khabar) jab khud in mein se kisi ko diya jata hai to uske mooh par siyahi(darkens) chaa jaati hai aur woh gham se bhar jaata hai" },
    { number: 18, arabic: "أَوَمَن يُنَشَّؤُا۟ فِى ٱلْحِلْيَةِ وَهُوَ فِى ٱلْخِصَامِ غَيْرُ مُبِينٍۢ", transliteration: "Awaman yunashshao fee alhilyati wahuwa fee alkhisami ghayru mubeenin", transliterationB: "Awa mai yunashsha'u fil hilyati wa huwa fil khisaami ghairu mubeen", english: "Is then one brought up among trinkets, and unable to give a clear account in a dispute (to be associated with Allah)", romanUrdu: "Kya Allah ke hisse mein woh aulad aayi jo zewaron (ornaments) mein paali jaati hai aur behas o hujjat mein apna mudda puri tarah wazeh bhi nahin kar sakti" },
    { number: 19, arabic: "وَجَعَلُوا۟ ٱلْمَلَٰٓئِكَةَ ٱلَّذِينَ هُمْ عِبَٰدُ ٱلرَّحْمَٰنِ إِنَٰثًا ۚ أَشَهِدُوا۟ خَلْقَهُمْ ۚ سَتُكْتَبُ شَهَٰدَتُهُمْ وَيُسْـَٔلُونَ", transliteration: "WajaAAaloo almalaikata allatheena hum AAibadu alrrahmani inathan ashahidoo khalqahum satuktabu shahadatuhum wayusaloona", transliterationB: "Wa ja'alul malaaa'ikatal lazeena hum 'ibaadur Rahmaani inaasaa; a shahidoo khalaqhum; satuktabu shahaa datuhum wa yus'aloon", english: "And they make into females angels who themselves serve Allah. Did they witness their creation? Their evidence will be recorded, and they will be called to account", romanUrdu: "Unhon ne farishton ko, jo khuda e Rehman ke khaas banday hain, auratein karar de liya. Kya unke jism ki saakht inhon ne dekhi hai? Inki gawahi likh li jayegi aur inhein iske jawab-dahi karni hogi" },
    { number: 20, arabic: "وَقَالُوا۟ لَوْ شَآءَ ٱلرَّحْمَٰنُ مَا عَبَدْنَٰهُم ۗ مَّا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ ۖ إِنْ هُمْ إِلَّا يَخْرُصُونَ", transliteration: "Waqaloo law shaa alrrahmanu ma AAabadnahum ma lahum bithalika min AAilmin in hum illa yakhrusoona", transliterationB: "Wa qaaloo law shaaa'ar Rahmaanu maa 'abadnaahum; maa lahum bizaalika min 'ilmin in hum illaa yakhrusoon", english: "(Ah!\") they say, \"If it had been the will of (Allah) Most Gracious, we should not have worshipped such (deities)!\" Of that they have no knowledge! they do nothing but lie", romanUrdu: "Yeh kehte hain “agar khuda-e-Rehman chahta (ke hum unki ibadat na karein) to hum kabhi unko na poojte” yeh is maamle ki haqeeqat ko qatai nahin jaante, mehaz teer tukkay ladate hain (are simply conjecturing /guess work)" },
    { number: 21, arabic: "أَمْ ءَاتَيْنَٰهُمْ كِتَٰبًۭا مِّن قَبْلِهِۦ فَهُم بِهِۦ مُسْتَمْسِكُونَ", transliteration: "Am ataynahum kitaban min qablihi fahum bihi mustamsikoona", transliterationB: "Am aatainaahum Kitaabam min qablihee fahum bihee mustamsikoon", english: "What! have We given them a Book before this, to which they are holding fast", romanUrdu: "Kya humne issey pehle koi kitaab inko di thi jiski sanad [apne is malaika (farihste) parasti ke liye] yeh apne paas rakhte hon" },
    { number: 22, arabic: "بَلْ قَالُوٓا۟ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٍۢ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّهْتَدُونَ", transliteration: "Bal qaloo inna wajadna abaana AAala ommatin wainna AAala atharihim muhtadoona", transliterationB: "Bal qaalooo innaa wajadnaaa aabaaa'anaa 'alaaa ummatinw wa innaa 'alaaa aasaarihim muhtadoon", english: "Nay! they say: \"We found our fathers following a certain religion, and we do guide ourselves by their footsteps", romanUrdu: "Nahin, balke yeh kehte hain ke humne apne baap dada ko ek tarike par paya hai aur hum unhi ke nakshe qadam par chal rahe hain" },
    { number: 23, arabic: "وَكَذَٰلِكَ مَآ أَرْسَلْنَا مِن قَبْلِكَ فِى قَرْيَةٍۢ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٍۢ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّقْتَدُونَ", transliteration: "Wakathalika ma arsalna min qablika fee qaryatin min natheerin illa qala mutrafooha inna wajadna abaana AAala ommatin wainna AAala atharihim muqtadoona", transliterationB: "Wa kazaalika maaa arsalnaa min qablika fee qaryatim min nazeerin illaa qaala mutrafoohaaa innaa wajadnaaa aabaaa'anaa 'alaaa ummatinw wa innaa 'alaaa aasaarihim muqtadoon", english: "Just in the same way, whenever We sent a Warner before thee to any people, the wealthy ones among them said: \"We found our fathers following a certain religion, and we will certainly follow in their footsteps", romanUrdu: "Isi tarah tumse pehle jis basti mein bhi humne koi nazeer(darane wala) bheja, uske khaate peete logon ne yahi kaha ke humne apne baap dada ko ek tareeqe par paya hai aur hum unhi ke naqshe qadam ki pairwi kar rahe hain" },
    { number: 24, arabic: "۞ قَٰلَ أَوَلَوْ جِئْتُكُم بِأَهْدَىٰ مِمَّا وَجَدتُّمْ عَلَيْهِ ءَابَآءَكُمْ ۖ قَالُوٓا۟ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ", transliteration: "Qala awalaw jitukum biahda mimma wajadtum AAalayhi abaakum qaloo inna bima orsiltum bihi kafiroona", transliterationB: "Qaala awa law ji'tukum bi ahdaa mimmaa wajattum 'alaihi aabaaa'akum qaalooo innaa bimaaa ursiltum bihee kaafiroon", english: "He said: \"What! Even if I brought you better guidance than that which ye found your fathers following?\" They said: \"For us, we deny that ye (prophets) are sent (on a mission at all)", romanUrdu: "Har Nabi ne unsey poocha, kya tum usi dagar par cahle jaogey khwah mein us raaste se zyada saheeh raasta tumhein bataun jispar tumne apne baap dada ko paya? Unhon ne saare Rasoolon ko yahi jawab diya ke jis deen ki taraf bulane ke liye tum bheje gaye ho hum uske kaafir hain" },
    { number: 25, arabic: "فَٱنتَقَمْنَا مِنْهُمْ ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُكَذِّبِينَ", transliteration: "Faintaqamna minhum faonthur kayfa kana AAaqibatu almukaththibeena", transliterationB: "Fantaqamnaa minhum fanzur kaifa kaana 'aaqibatul mukazzibeen", english: "So We exacted retribution from them: now see what was the end of those who rejected (Truth)", romanUrdu: "Aakhir e kaar humne unki khabar le daali aur dekh lo ke jhutlane walon ka kya anjaam hua" },
    { number: 26, arabic: "وَإِذْ قَالَ إِبْرَٰهِيمُ لِأَبِيهِ وَقَوْمِهِۦٓ إِنَّنِى بَرَآءٌۭ مِّمَّا تَعْبُدُونَ", transliteration: "Waith qala ibraheemu liabeehi waqawmihi innanee baraon mimma taAAbudoona", transliterationB: "Wa iz qaala Ibraaheemu liabeehi wa qawmiheee innane baraaa'um mimmaa ta'budo", english: "Behold! Abraham said to his father and his people: \"I do indeed clear myself of what ye worship", romanUrdu: "Yaad karo woh waqt jab Ibrahim ne apne baap aur apni qaum se kaha tha ke “tum jinki bandagi karte ho mera unsey koi taaq nahin" },
    { number: 27, arabic: "إِلَّا ٱلَّذِى فَطَرَنِى فَإِنَّهُۥ سَيَهْدِينِ", transliteration: "Illa allathee fataranee fainnahu sayahdeeni", transliterationB: "Illal lazee fataranee innahoo sa yahdeen", english: "(I worship) only Him Who made me, and He will certainly guide me", romanUrdu: "Mera talluq sirf ussey hai jisne mujhe paida kiya, wahi meri rehnumayi karega”" },
    { number: 28, arabic: "وَجَعَلَهَا كَلِمَةًۢ بَاقِيَةًۭ فِى عَقِبِهِۦ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "WajaAAalaha kalimatan baqiyatan fee AAaqibihi laAAallahum yarjiAAoona", transliterationB: "Wa ja'alahaa Kalimatam baaqiyatan fee 'aqibihee la'al lahum yarji'oon", english: "And he left it as a Word to endure among those who came after him, that they may turn back (to Allah)", romanUrdu: "Aur Ibrahim yahi kalima apne peechey apni aulad mein chodh gaya taa-ke woh iski taraf ruju karein" },
    { number: 29, arabic: "بَلْ مَتَّعْتُ هَٰٓؤُلَآءِ وَءَابَآءَهُمْ حَتَّىٰ جَآءَهُمُ ٱلْحَقُّ وَرَسُولٌۭ مُّبِينٌۭ", transliteration: "Bal mattaAAtu haolai waabaahum hatta jaahumu alhaqqu warasoolun mubeenun", transliterationB: "Bal matta'tu haaa'ulaaa'i wa aabaaa'ahum hattaa jaaa'a humul haqqu wa Rasoolum mubeen", english: "Yea, I have given the good things of this life to these (men) and their fathers, until the Truth has come to them, and a messenger making things clear", romanUrdu: "(Is ke bawajood jab yeh log dusron ki bandagi karne lagey to maine inko mita nahin diya) balke main inhein aur inke baap dada ko mata-e-hayat (sustenance) deta raha yahan tak ke inke paas haqq, aur khol khol kar bayan karne wala Rasool aa gaya" },
    { number: 30, arabic: "وَلَمَّا جَآءَهُمُ ٱلْحَقُّ قَالُوا۟ هَٰذَا سِحْرٌۭ وَإِنَّا بِهِۦ كَٰفِرُونَ", transliteration: "Walamma jaahumu alhaqqu qaloo hatha sihrun wainna bihi kafiroona", transliterationB: "Wa lammaa jaaa'ahumul haqqu qaaloo haazaa sihrunw wa innaa bihee kaafiroon", english: "But when the Truth came to them, they said: \"This is sorcery, and we do reject it", romanUrdu: "Magar jab woh haqq inke paas aaya to inhon ne keh diya yeh to jaadu hai aur hum isko maanne se inkar karte hain" },
    { number: 31, arabic: "وَقَالُوا۟ لَوْلَا نُزِّلَ هَٰذَا ٱلْقُرْءَانُ عَلَىٰ رَجُلٍۢ مِّنَ ٱلْقَرْيَتَيْنِ عَظِيمٍ", transliteration: "Waqaloo lawla nuzzila hatha alquranu AAala rajulin mina alqaryatayni AAatheemun", transliterationB: "Wa qaaloo law laa nuzzila haazal Quraanu 'alaa rajulim minal qaryataini 'azeem", english: "Also, they say: \"Why is not this Qur'an sent down to some leading man in either of the two (chief) cities", romanUrdu: "Kehte hain, yeh Quran dono sheharon ke baday aadmiyon mein se kisi par kyoun na nazil kiya gaya" },
    { number: 32, arabic: "أَهُمْ يَقْسِمُونَ رَحْمَتَ رَبِّكَ ۚ نَحْنُ قَسَمْنَا بَيْنَهُم مَّعِيشَتَهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَرَفَعْنَا بَعْضَهُمْ فَوْقَ بَعْضٍۢ دَرَجَٰتٍۢ لِّيَتَّخِذَ بَعْضُهُم بَعْضًۭا سُخْرِيًّۭا ۗ وَرَحْمَتُ رَبِّكَ خَيْرٌۭ مِّمَّا يَجْمَعُونَ", transliteration: "Ahum yaqsimoona rahmata rabbika nahnu qasamna baynahum maAAeeshatahum fee alhayati alddunya warafaAAna baAAdahum fawqa baAAdin darajatin liyattakhitha baAAduhum baAAdan sukhriyyan warahmatu rabbika khayrun mimma yajmaAAoona", transliterationB: "Ahum yaqsimoona rahmata Rabbik; Nahnu qasamnaa bainahum ma'eeshatahum fil hayaatid dunyaa wa rafa'naa ba'dahum fawqa ba'din darajaatil liyattakhiza ba'duhum ba'dan sukhriyyaa; wa rahmatu Rabbika khairum mimmaa yajma'oon", english: "Is it they who would portion out the Mercy of thy Lord? It is We Who portion out between them their livelihood in the life of this world: and We raise some of them above others in ranks, so that some may command work from others. But the Mercy of thy Lord is better than the (wealth) which they amass", romanUrdu: "Kya tere Rubb ki rehmat yeh log takseem karte hain? Duniya ki zindagi mein inki guzar basar ke zaraye to humne inke darmiyan takseem kiye hain, Aur in mein se kuch logon ko kuch dusre logon par humne badarja-ha fauqiyat di hai taa-ke yeh ek dusre se khidmat lein aur tere Rubb ki rehmat us daulat se zyada keemati hai jo (inke rahees) samait rahe hain" },
    { number: 33, arabic: "وَلَوْلَآ أَن يَكُونَ ٱلنَّاسُ أُمَّةًۭ وَٰحِدَةًۭ لَّجَعَلْنَا لِمَن يَكْفُرُ بِٱلرَّحْمَٰنِ لِبُيُوتِهِمْ سُقُفًۭا مِّن فِضَّةٍۢ وَمَعَارِجَ عَلَيْهَا يَظْهَرُونَ", transliteration: "Walawla an yakoona alnnasu ommatan wahidatan lajaAAalna liman yakfuru bialrrahmani libuyootihim suqufan min fiddatin wamaAAarija AAalayha yathharoona", transliterationB: "Wa law laaa any yakoonan naasu ummatanw waahidatal laja'alnaa limany yakfuru bir Rahmaani libu yootihim suqufam min fiddatinw wa ma'aarija 'alaihaa yazharoon", english: "And were it not that (all) men might become of one (evil) way of life, We would provide, for everyone that blasphemes against (Allah) Most Gracious, silver roofs for their houses and (silver) stair-ways on which to go up", romanUrdu: "Agar yeh andesha na hota ke saare log ek hi tareeqe ke ho jayenge to hum khuda e Rehman se kufr karne walon ke gharon ki chatein (canopy), aur unki seedhiyan (ladders) jinse woh apne baala khaano par chadte hain" },
    { number: 34, arabic: "وَلِبُيُوتِهِمْ أَبْوَٰبًۭا وَسُرُرًا عَلَيْهَا يَتَّكِـُٔونَ", transliteration: "Walibuyootihim abwaban wasururan AAalayha yattakioona", transliterationB: "Wa libu yootihim abwaabanw wa sururan 'alaihaa yattaki'oon", english: "And (silver) doors to their houses, and thrones (of silver) on which they could recline", romanUrdu: "Aur unke darwaze , aur unke takhat jinpar woh takiye (pillows) laga kar baithte hain" },
    { number: 35, arabic: "وَزُخْرُفًۭا ۚ وَإِن كُلُّ ذَٰلِكَ لَمَّا مَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَٱلْءَاخِرَةُ عِندَ رَبِّكَ لِلْمُتَّقِينَ", transliteration: "Wazukhrufan wain kullu thalika lamma mataAAu alhayati alddunya waalakhiratu AAinda rabbika lilmuttaqeena", transliterationB: "Wa zukhrufaa; wa in kullu zaalika lammaa mataa'ul hayaatid dunyaa; wal aakhiratu 'inda Rabbika lilmuttaqeen", english: "And also adornments of gold. But all this were nothing but conveniences of the present life: The Hereafter, in the sight of thy Lord is for the Righteous", romanUrdu: "Sab chandi aur soney (gold) ke banwa detay .Yeh to mehaz hayat e duniya ki mataah hain.Aur aakhirat tere Rubb ke haan sirf muttaqeen ke liye hai" },
    { number: 36, arabic: "وَمَن يَعْشُ عَن ذِكْرِ ٱلرَّحْمَٰنِ نُقَيِّضْ لَهُۥ شَيْطَٰنًۭا فَهُوَ لَهُۥ قَرِينٌۭ", transliteration: "Waman yaAAshu AAan thikri alrrahmani nuqayyid lahu shaytanan fahuwa lahu qareenun", transliterationB: "Wa mai ya'shu 'an zikrir Rahmaani nuqaiyid lahoo Shaitaanan fahuwa lahoo qareen", english: "If anyone withdraws himself from remembrance of (Allah) Most Gracious, We appoint for him an evil one, to be an intimate companion to him", romanUrdu: "Jo shaks Rehman ke zikar se tagaful (gaflat) barat-ta hai, hum ispar ek shaytan musallat kar detay hain aur woh uska rafiq ban jata hai" },
    { number: 37, arabic: "وَإِنَّهُمْ لَيَصُدُّونَهُمْ عَنِ ٱلسَّبِيلِ وَيَحْسَبُونَ أَنَّهُم مُّهْتَدُونَ", transliteration: "Wainnahum layasuddoonahum AAani alssabeeli wayahsaboona annahum muhtadoona", transliterationB: "Wa innahum la yasuddoo nahum 'anis sabeeli wa yahsaboona annahum muhtadoon", english: "Such (evil ones) really hinder them from the Path, but they think that they are being guided aright", romanUrdu: "Yeh shayateen aisay logon ko raah e raast par aane se rokte hain, aur woh apni jagah yeh samajhte hain ke hum theek jaa rahe hain" },
    { number: 38, arabic: "حَتَّىٰٓ إِذَا جَآءَنَا قَالَ يَٰلَيْتَ بَيْنِى وَبَيْنَكَ بُعْدَ ٱلْمَشْرِقَيْنِ فَبِئْسَ ٱلْقَرِينُ", transliteration: "Hatta itha jaana qala ya layta baynee wabaynaka buAAda almashriqayni fabisa alqareenu", transliterationB: "Hattaaa izaa jaaa'anaa qaala yaa laita bainee wa bainaka bu'dal mashriqaini fabi'sal qareen", english: "At length, when (such a one) comes to Us, he says (to his evil companion): \"Would that between me and thee were the distance of East and West!\" Ah! evil is the companion (indeed)", romanUrdu: "Aakhir e kaar jab yeh shaks hamare haan pahuchega to apne shaytan se kahega “kaash mere aur tere darmiyan mashriq o magrib ka boadh (doori/ distance) hota, tu to badhtareen saathi nikla”" },
    { number: 39, arabic: "وَلَن يَنفَعَكُمُ ٱلْيَوْمَ إِذ ظَّلَمْتُمْ أَنَّكُمْ فِى ٱلْعَذَابِ مُشْتَرِكُونَ", transliteration: "Walan yanfaAAakumu alyawma ith thalamtum annakum fee alAAathabi mushtarikoona", transliterationB: "Wa lai yanfa'akumul Yawma iz zalamtum annakum fil 'azaabi mushtarikoon", english: "When ye have done wrong, it will avail you nothing, that Day, that ye shall be partners in Punishment", romanUrdu: "Us waqt in logon se kaha jayega ke jab tum zulm kar chuke to aaj yeh baat tumhare liye kuch bhi nafeh nahin hai ke tum aur tumahre shayateen azaab mein mushtarik hain" },
    { number: 40, arabic: "أَفَأَنتَ تُسْمِعُ ٱلصُّمَّ أَوْ تَهْدِى ٱلْعُمْىَ وَمَن كَانَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Afaanta tusmiAAu alssumma aw tahdee alAAumya waman kana fee dalalin mubeenin", transliterationB: "Afa anta tusmi'us summa aw tahdil 'umya wa man kaana fee dalaalim mubeen", english: "Canst thou then make the deaf to hear, or give direction to the blind or to such as (wander) in manifest error", romanUrdu: "Ab kya aey Nabi tum behron (deaf) ko sunaoge? Ya andhon (blind) aur sareeh gumrahi mein padey huey logon ko raah dihoge" },
    { number: 41, arabic: "فَإِمَّا نَذْهَبَنَّ بِكَ فَإِنَّا مِنْهُم مُّنتَقِمُونَ", transliteration: "Faimma nathhabanna bika fainna minhum muntaqimoona", transliterationB: "Fa immaa nazhabanna bika fa innaa minhum muntaqimoon", english: "Even if We take thee away, We shall be sure to exact retribution from them", romanUrdu: "Ab to humein inko saza deni hai khwah tumhein duniya se utha lein" },
    { number: 42, arabic: "أَوْ نُرِيَنَّكَ ٱلَّذِى وَعَدْنَٰهُمْ فَإِنَّا عَلَيْهِم مُّقْتَدِرُونَ", transliteration: "Aw nuriyannaka allathee waAAadnahum fainna AAalayhim muqtadiroona", transliterationB: "Aw nuriyannakal lazee wa'adnaahum fa innaa 'alaihim muqtadiroon", english: "Or We shall show thee that (accomplished) which We have promised them: for verily We shall prevail over them", romanUrdu: "Ya tumko aankhon se inka woh anjaam dikha dein jiska humne issey waada kiya hai. Humein inpar poori qudrat haasil hai" },
    { number: 43, arabic: "فَٱسْتَمْسِكْ بِٱلَّذِىٓ أُوحِىَ إِلَيْكَ ۖ إِنَّكَ عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Faistamsik biallathee oohiya ilayka innaka AAala siratin mustaqeemin", transliterationB: "Fastamsik billazeee oohi ya ilaika innaka 'alaa Siraatim Mustaqeem", english: "So hold thou fast to the Revelation sent down to thee; verily thou art on a Straight Way", romanUrdu: "Tum bahar-haal us kitaab ko mazbooti se thamay raho jo wahi ke zariye se tumhare paas bheji gayi hai, yaqeenan tum seedhey raaste par ho" },
    { number: 44, arabic: "وَإِنَّهُۥ لَذِكْرٌۭ لَّكَ وَلِقَوْمِكَ ۖ وَسَوْفَ تُسْـَٔلُونَ", transliteration: "Wainnahu lathikrun laka waliqawmika wasawfa tusaloona", transliterationB: "Wa innahoo lazikrul laka wa liqawmika wa sawfa tus'aloon", english: "The (Qur'an) is indeed the message, for thee and for thy people; and soon shall ye (all) be brought to account", romanUrdu: "Haqeeqat yeh hai ke yeh kitaab tumahre liye aur tumhari qaum ke liye ek bahut bada sharaf hai aur anqareeb tum logon ko iski jawab-dahi karni hogi" },
    { number: 45, arabic: "وَسْـَٔلْ مَنْ أَرْسَلْنَا مِن قَبْلِكَ مِن رُّسُلِنَآ أَجَعَلْنَا مِن دُونِ ٱلرَّحْمَٰنِ ءَالِهَةًۭ يُعْبَدُونَ", transliteration: "Waisal man arsalna min qablika min rusulina ajaAAalna min dooni alrrahmani alihatan yuAAbadoona", transliterationB: "Was'al man arsalnaa min qablika mir Rusulinaaa aja'alnaa min doonir Rahmaani aalihatany yu badoon", english: "And question thou our messengers whom We sent before thee; did We appoint any deities other than (Allah) Most Gracious, to be worshipped", romanUrdu: "Tumse pehle humne jitne Rasool bheje thay un sab se pooch dekho, kya humne khuda e Rehman ke siwa kuch dusre maabood bhi muqarrar kiye thay ke unki bandagi ki jaaye" },
    { number: 46, arabic: "وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَٰتِنَآ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَقَالَ إِنِّى رَسُولُ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Walaqad arsalna moosa biayatina ila firAAawna wamalaihi faqala innee rasoolu rabbi alAAalameena", transliterationB: "Wa laqad arsalnaa Moosaa bi aayaatinaaa ilaa Fir'awna wa mala'ihee faqaala innee Rasoolu Rabbil 'aalameen", english: "We did send Moses aforetime, with Our Signs, to Pharaoh and his Chiefs: He said, \"I am a messenger of the Lord of the Worlds", romanUrdu: "Humne Moosa ko apni nishaniyon ke saath Firoun aur uske ayaan-e-sultanat ke paas bheja, aur usne jaa kar kaha ke main Rubb ul aalamin ka Rasool hoon" },
    { number: 47, arabic: "فَلَمَّا جَآءَهُم بِـَٔايَٰتِنَآ إِذَا هُم مِّنْهَا يَضْحَكُونَ", transliteration: "Falamma jaahum biayatina itha hum minha yadhakoona", transliterationB: "Falammma jaaa'ahum bi aayaatinaaa izaa hum minhaa yadhakoon", english: "But when he came to them with Our Signs, behold they ridiculed them", romanUrdu: "Phir jab usne hamari nishaniyan unke saamne pesh ki to woh thatte (laughter) maarne lagey" },
    { number: 48, arabic: "وَمَا نُرِيهِم مِّنْ ءَايَةٍ إِلَّا هِىَ أَكْبَرُ مِنْ أُخْتِهَا ۖ وَأَخَذْنَٰهُم بِٱلْعَذَابِ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Wama nureehim min ayatin illa hiya akbaru min okhtiha waakhathnahum bialAAathabi laAAallahum yarjiAAoona", transliterationB: "Wa maa nureehim min aayatin illaa hiya akbaru min ukhtihaa wa akhaznaahum bil'azaabi la'allahum yarji'oon", english: "We showed them Sign after Sign, each greater than its fellow, and We seized them with Punishment, in order that they might turn (to Us)", romanUrdu: "Hum ek par ek aisi nishani unko dikhate chale gaye jo pehli se badh chadh kar thi, aur humne unko azaab mein dhar liya taa-ke woh apni rawish se baaz aayein" },
    { number: 49, arabic: "وَقَالُوا۟ يَٰٓأَيُّهَ ٱلسَّاحِرُ ٱدْعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَ إِنَّنَا لَمُهْتَدُونَ", transliteration: "Waqaloo ya ayyuha alsahiru odAAu lana rabbaka bima AAahida AAindaka innana lamuhtadoona", transliterationB: "Wa qaaloo yaaa ayyuhas saahirud'u lanaa Rabbaka bimaa 'ahida 'indaka innanaa lamuhtadoon", english: "And they said, \"O thou sorcerer! Invoke thy Lord for us according to His covenant with thee; for we shall truly accept guidance", romanUrdu: "Har azaab ke mauqe par woh kehte, Aey saahir (Jaadugar/magician), apne Rubb ki taraf se jo mansab tujhe haasil hai uski bina par hamare liye ussey duaa kar, hum zaroor raah-e-raast par aa jayenge" },
    { number: 50, arabic: "فَلَمَّا كَشَفْنَا عَنْهُمُ ٱلْعَذَابَ إِذَا هُمْ يَنكُثُونَ", transliteration: "Falamma kashafna AAanhumu alAAathaba itha hum yankuthoona", transliterationB: "Falammaa kashafnaa 'anhumul 'azaaba izaa hum yankusoon", english: "But when We removed the Penalty from them, behold, they broke their word", romanUrdu: "Magar joonh hi ke hum unpar se azaab hata detay woh apni baat se phir jaatey thay" },
    { number: 51, arabic: "وَنَادَىٰ فِرْعَوْنُ فِى قَوْمِهِۦ قَالَ يَٰقَوْمِ أَلَيْسَ لِى مُلْكُ مِصْرَ وَهَٰذِهِ ٱلْأَنْهَٰرُ تَجْرِى مِن تَحْتِىٓ ۖ أَفَلَا تُبْصِرُونَ", transliteration: "Wanada firAAawnu fee qawmihi qala ya qawmi alaysa lee mulku misra wahathihi alanharu tajree min tahtee afala tubsiroona", transliterationB: "Wa naadaa Fir'awnu fee qawmihee qaala yaa qawmi alaisa lee mulku Misra wa haazihil anhaaru tajree min tahtee afalaa tubsiroon", english: "And Pharaoh proclaimed among his people, saying: \"O my people! Does not the dominion of Egypt belong to me, (witness) these streams flowing underneath my (palace)? What! see ye not then", romanUrdu: "Ek roz Firoun ne apni qaum ke darmiyan pukar kar kaha, “logon, kya misr (egypt) ki baadshahi meri nahin hai, aur yeh nehrein (streams) mere nichey nahin beh rahi hain? Kya tum logon ko nazar nahin aata" },
    { number: 52, arabic: "أَمْ أَنَا۠ خَيْرٌۭ مِّنْ هَٰذَا ٱلَّذِى هُوَ مَهِينٌۭ وَلَا يَكَادُ يُبِينُ", transliteration: "Am ana khayrun min hatha allathee huwa maheenun wala yakadu yubeenu", transliterationB: "Am ana khairum min haazal lazee huwa maheenunw wa laa yuakaadu yubeen", english: "Am I not better than this (Moses), who is a contemptible wretch and can scarcely express himself clearly", romanUrdu: "Mein behtar hoon ya yeh shaks jo zaleel o haqeer hai aur apni baat bhi khol kar bayan nahin kar sakta" },
    { number: 53, arabic: "فَلَوْلَآ أُلْقِىَ عَلَيْهِ أَسْوِرَةٌۭ مِّن ذَهَبٍ أَوْ جَآءَ مَعَهُ ٱلْمَلَٰٓئِكَةُ مُقْتَرِنِينَ", transliteration: "Falawla olqiya AAalayhi aswiratun min thahabin aw jaa maAAahu almalaikatu muqtarineena", transliterationB: "Falaw laa ulqiya 'alaihi aswiratum min zahabin awjaaa'a ma'ahul malaaa'ikatu muqtarineen", english: "Then why are not gold bracelets bestowed on him, or (why) come (not) with him angels accompanying him in procession", romanUrdu: "Kyun na ispar soney (gold) ke kangan (bangles) utare gaye? Ya farishton ka ek dasta iski ardali mein na aaya?”" },
    { number: 54, arabic: "فَٱسْتَخَفَّ قَوْمَهُۥ فَأَطَاعُوهُ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًۭا فَٰسِقِينَ", transliteration: "Faistakhaffa qawmahu faataAAoohu innahum kanoo qawman fasiqeena", transliterationB: "Fastakhaffa qawmahoo fa ataa'ooh; innahum kaanoo qawman faasiqeen", english: "Thus did he make fools of his people, and they obeyed him: truly were they a people rebellious (against Allah)", romanUrdu: "Usne apni qaum ko halka samjha aur unhon ne uski itaat ki, dar haqeeqat woh thay hi faasiq log" },
    { number: 55, arabic: "فَلَمَّآ ءَاسَفُونَا ٱنتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَٰهُمْ أَجْمَعِينَ", transliteration: "Falamma asafoona intaqamna minhum faaghraqnahum ajmaAAeena", transliterationB: "Falammaaa aasafoonan taqamnaa minhum fa aghraqnaahum ajma'een", english: "When at length they provoked Us, We exacted retribution from them, and We drowned them all", romanUrdu: "Aakhir e kaar jab unhon ne humein gazabnaak kardiya to humne unse inteqam liya aur unko ikattha garq (drown) kiya" },
    { number: 56, arabic: "فَجَعَلْنَٰهُمْ سَلَفًۭا وَمَثَلًۭا لِّلْءَاخِرِينَ", transliteration: "FajaAAalnahum salafan wamathalan lilakhireena", transliterationB: "Faja'alnaahum salafanw wa masalal lil aakhireen", english: "And We made them (a people) of the Past and an Example to later ages", romanUrdu: "Aur baad walon ke liye pesh-ro aur namoona ibrat banakar rakh diya" },
    { number: 57, arabic: "۞ وَلَمَّا ضُرِبَ ٱبْنُ مَرْيَمَ مَثَلًا إِذَا قَوْمُكَ مِنْهُ يَصِدُّونَ", transliteration: "Walamma duriba ibnu maryama mathalan itha qawmuka minhu yasiddoona", transliterationB: "Wa lammaa duribab nu Maryama masalan izaa qawmu ka minhu yasidoon", english: "When (Jesus) the son of Mary is held up as an example, behold, thy people raise a clamour thereat (in ridicule)", romanUrdu: "Aur jonhi ke ibne Maryam (Jesus) ki misal di gayi, tumhari qaum ke logon ne uspar gul macha diya (chilla utthey/ raised a clamour)" },
    { number: 58, arabic: "وَقَالُوٓا۟ ءَأَٰلِهَتُنَا خَيْرٌ أَمْ هُوَ ۚ مَا ضَرَبُوهُ لَكَ إِلَّا جَدَلًۢا ۚ بَلْ هُمْ قَوْمٌ خَصِمُونَ", transliteration: "Waqaloo aalihatuna khayrun am huwa ma daraboohu laka illa jadalan bal hum qawmun khasimoona", transliterationB: "Wa qaalooo 'a-aalihatunaa khairun am hoo; maa daraboohu laka illaa jadalaa; balhum qawmun khasimoon", english: "And they say, \"Are our gods best, or he?\" This they set forth to thee, only by way of disputation: yea, they are a contentious people", romanUrdu: "Aur lagey kehne ke hamare maabood acche hain ya woh? Yeh misaal woh tumhare saamne mehaz kach-behasi (argument/ contentiousness) ke liye laaye hain, haqeeat yeh hai ke yeh hain hi jhagdalu log" },
    { number: 59, arabic: "إِنْ هُوَ إِلَّا عَبْدٌ أَنْعَمْنَا عَلَيْهِ وَجَعَلْنَٰهُ مَثَلًۭا لِّبَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "In huwa illa AAabdun anAAamna AAalayhi wajaAAalnahu mathalan libanee israeela", transliterationB: "In huwa illaa 'abdun an'amnaa 'alaihi wa ja'alnaahu masalal li Baneee Israaa'eel", english: "He was no more than a servant: We granted Our favour to him, and We made him an example to the Children of Israel", romanUrdu: "Ibne Maryam (Jesus) iske siwa kuch na tha ek banda tha jispar humne inaam kiya aur bani israel ke liye apni qudrat ka ek namuna bana diya" },
    { number: 60, arabic: "وَلَوْ نَشَآءُ لَجَعَلْنَا مِنكُم مَّلَٰٓئِكَةًۭ فِى ٱلْأَرْضِ يَخْلُفُونَ", transliteration: "Walaw nashao lajaAAalna minkum malaikatan fee alardi yakhlufoona", transliterationB: "Wa law nashaaa'u laja'alnaa minkum malaaa'ikatan fil ardi yakhlufoon", english: "And if it were Our Will, We could make angels from amongst you, succeeding each other on the earth", romanUrdu: "Hum chahein to tumse farishte paida kardein jo zameen mein tumhare janasheen(successors) hon" },
    { number: 61, arabic: "وَإِنَّهُۥ لَعِلْمٌۭ لِّلسَّاعَةِ فَلَا تَمْتَرُنَّ بِهَا وَٱتَّبِعُونِ ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ", transliteration: "Wainnahu laAAilmun lilssaAAati fala tamtarunna biha waittabiAAooni hatha siratun mustaqeemun", transliterationB: "Wa innahoo la'ilmul lis Saa'ati fala tamtarunna bihaa wattabi'oon; haazaa Siraatum Mustaqeem", english: "And (Jesus) shall be a Sign (for the coming of) the Hour (of Judgment): therefore have no doubt about the (Hour), but follow ye Me: this is a Straight Way", romanUrdu: "Aur woh dar-asal qayamat ki ek nishani hai, pas tum usmein shakk na karo meri baat maan lo, yahi seedha raasta hai" },
    { number: 62, arabic: "وَلَا يَصُدَّنَّكُمُ ٱلشَّيْطَٰنُ ۖ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌۭ", transliteration: "Wala yasuddannakumu alshshaytanu innahu lakum AAaduwwun mubeenun", transliterationB: "Wa laa yasuddan nakumush Shaitaanu innahoo lakum 'aduwwum mubeen", english: "Let not the Evil One hinder you: for he is to you an enemy avowed", romanUrdu: "Aisa na ho shaytan tumko ussey roak de ke woh tumhara khula dushman hai" },
    { number: 63, arabic: "وَلَمَّا جَآءَ عِيسَىٰ بِٱلْبَيِّنَٰتِ قَالَ قَدْ جِئْتُكُم بِٱلْحِكْمَةِ وَلِأُبَيِّنَ لَكُم بَعْضَ ٱلَّذِى تَخْتَلِفُونَ فِيهِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Walamma jaa AAeesa bialbayyinati qala qad jitukum bialhikmati waliobayyina lakum baAAda allathee takhtalifoona feehi faittaqoo Allaha waateeAAooni", transliterationB: "Wa lammaa jaaa'a 'Eesaa bilbaiyinaati qaala qad ji'tukum bil Hikmati wa li-ubaiyina lakum ba'dal lazee takhtalifoona feehi fattaqul laaha wa atee'oon", english: "When Jesus came with Clear Signs, he said: \"Now have I come to you with Wisdom, and in order to make clear to you some of the (points) on which ye dispute: therefore fear Allah and obey me", romanUrdu: "Aur jab Isa (Jesus) sareeh nishaniyan liye huey aaya tha to usne kaha tha ke “main tum logon ke paas hikmat lekar aaya hoon, aur isliye aaya hoon ke tumpar baaz un baaton ki haqeeqat khol doon jin mein tum ikhtilaf kar rahey ho, lihaza tum Allah se daro aur meri itaat karo" },
    { number: 64, arabic: "إِنَّ ٱللَّهَ هُوَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ", transliteration: "Inna Allaha huwa rabbee warabbukum faoAAbudoohu hatha siratun mustaqeemun", transliterationB: "Innal laaha Huwa Rabbee wa Rabbukum fa'budooh; haaza Siraatum Mustaqeem", english: "For Allah, He is my Lord and your Lord: so worship ye Him: this is a Straight Way", romanUrdu: "Haqeeqat yeh hai ke Allah hi mera Rubb bhi hai aur tumhara Rubb bhi.Usi ki tum ibadat karo, yahi seedha raasta hai”" },
    { number: 65, arabic: "فَٱخْتَلَفَ ٱلْأَحْزَابُ مِنۢ بَيْنِهِمْ ۖ فَوَيْلٌۭ لِّلَّذِينَ ظَلَمُوا۟ مِنْ عَذَابِ يَوْمٍ أَلِيمٍ", transliteration: "Faikhtalafa alahzabu min baynihim fawaylun lillatheena thalamoo min AAathabi yawmin aleemin", transliterationB: "Fakhtalafal ahzaabu mim bainihim fawailul lillazeena zalamoo min 'azaabi Yawmin aleem", english: "But sects from among themselves fell into disagreement: then woe to the wrong-doers, from the Penalty of a Grievous Day", romanUrdu: "Magar (uski is saaf taleem ke bawajood) girohon (factions) ne aapas mein ikhtilaf kiya, pas tabahi hai un logon ke liye jinhon ne zulm kiya ek dardnaak din ke azaab se" },
    { number: 66, arabic: "هَلْ يَنظُرُونَ إِلَّا ٱلسَّاعَةَ أَن تَأْتِيَهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", transliteration: "Hal yanthuroona illa alssaAAata an tatiyahum baghtatan wahum la yashAAuroona", transliterationB: "Hal yanzuroona illas Saa'ata an taatiyahum baghtatanw wa hum laa yash'uroon", english: "Do they only wait for the Hour - that it should come on them all of a sudden, while they perceive not", romanUrdu: "Kya yeh log ab bas isi cheez ke muntazir hain ke achanak inpar qiyamat aa jaye aur inhein khabar bhi na ho" },
    { number: 67, arabic: "ٱلْأَخِلَّآءُ يَوْمَئِذٍۭ بَعْضُهُمْ لِبَعْضٍ عَدُوٌّ إِلَّا ٱلْمُتَّقِينَ", transliteration: "Alakhillao yawmaithin baAAduhum libaAAdin AAaduwwun illa almuttaqeena", transliterationB: "Al akhillaaa'u Yawma'izim ba'duhum liba'din 'aduwwun illal muttaqeen", english: "Friends on that day will be foes, one to another,- except the Righteous", romanUrdu: "Woh din jab aayega to muttaqin ko chodh kar baaki sab dost ek dursre ke dushman ho jayenge" },
    { number: 68, arabic: "يَٰعِبَادِ لَا خَوْفٌ عَلَيْكُمُ ٱلْيَوْمَ وَلَآ أَنتُمْ تَحْزَنُونَ", transliteration: "Ya AAibadi la khawfun AAalaykumu alyawma wala antum tahzanoona", transliterationB: "Yaa 'ibaadi laa khawfun 'alaikumul Yawma wa laaa antum tahzanoon", english: "My devotees! no fear shall be on you that Day, nor shall ye grieve", romanUrdu: "Us roz un logon se jo hamari aayat par imaan laaye thay aur mutii-e-farmaan bankar rahey thay" },
    { number: 69, arabic: "ٱلَّذِينَ ءَامَنُوا۟ بِـَٔايَٰتِنَا وَكَانُوا۟ مُسْلِمِينَ", transliteration: "Allatheena amanoo biayatina wakanoo muslimeena", transliterationB: "Allazeena aamanoo bi Aayaatinaa wa kaanoo muslimeen", english: "(Being) those who have believed in Our Signs and bowed (their wills to Ours) in Islam", romanUrdu: "Kaha jayega ke “aey mere bandon (servents), aaj tumhare liye koi khauff nahin aur na tumhein koi gham lahiq hoga" },
    { number: 70, arabic: "ٱدْخُلُوا۟ ٱلْجَنَّةَ أَنتُمْ وَأَزْوَٰجُكُمْ تُحْبَرُونَ", transliteration: "Odkhuloo aljannata antum waazwajukum tuhbaroona", transliterationB: "Udkhulul Jannata antum wa azwaajukum tuhbaroon", english: "Enter ye the Garden, ye and your wives, in (beauty and) rejoicing", romanUrdu: "Dakhil ho jao jannat mein tum aur tumhari biwiyan, tumhein khush kardiya jaayega”" },
    { number: 71, arabic: "يُطَافُ عَلَيْهِم بِصِحَافٍۢ مِّن ذَهَبٍۢ وَأَكْوَابٍۢ ۖ وَفِيهَا مَا تَشْتَهِيهِ ٱلْأَنفُسُ وَتَلَذُّ ٱلْأَعْيُنُ ۖ وَأَنتُمْ فِيهَا خَٰلِدُونَ", transliteration: "Yutafu AAalayhim bisihafin min thahabin waakwabin wafeeha ma tashtaheehi alanfusu watalaththu alaAAyunu waantum feeha khalidoona", transliterationB: "Yutaafu 'alaihim bishaa fim min zahabinw wa akwaab, wa feehaa maatashtaheehil anfusu wa talazzul a'yunu wa antum feehaa khaalidoon", english: "To them will be passed round, dishes and goblets of gold: there will be there all that the souls could desire, all that their eyes could delight in: and ye shall abide therein (for eye)", romanUrdu: "Unke aagay soonay (golden) ke thal (Platters) aur sagar gardish karaye jayenge aur har mann bhaati aur nigaahon ko lazzat dene wali cheez wahan maujood hogi. Unse kaha jayega, “tum ab yahan hamesha rahoge" },
    { number: 72, arabic: "وَتِلْكَ ٱلْجَنَّةُ ٱلَّتِىٓ أُورِثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Watilka aljannatu allatee oorithtumooha bima kuntum taAAmaloona", transliterationB: "Wa tilkal jannatul lateee ooristumoohaa bimaa kuntum ta'maloon", english: "Such will be the Garden of which ye are made heirs for your (good) deeds (in life)", romanUrdu: "Tum is jannat ke waaris apne un aamal ki wajah se huey ho jo tum duniya mein karte rahe" },
    { number: 73, arabic: "لَكُمْ فِيهَا فَٰكِهَةٌۭ كَثِيرَةٌۭ مِّنْهَا تَأْكُلُونَ", transliteration: "Lakum feeha fakihatun katheeratun minha takuloona", transliterationB: "Lakum feehaa faakihatun kaseeratum minhaa taakuloon", english: "Ye shall have therein abundance of fruit, from which ye shall have satisfaction", romanUrdu: "Tumhare liye yahan bakasrat fawake(abundant fruits) maujood hain jinhein tum khaogey”" },
    { number: 74, arabic: "إِنَّ ٱلْمُجْرِمِينَ فِى عَذَابِ جَهَنَّمَ خَٰلِدُونَ", transliteration: "Inna almujrimeena fee AAathabi jahannama khalidoona", transliterationB: "Innal mujrimeena fee 'azaabi jahannama khaalidoon", english: "The sinners will be in the Punishment of Hell, to dwell therein (for aye)", romanUrdu: "Rahe mujreem , to woh hamesha jahannum ke azaab mein mubtala rahenge" },
    { number: 75, arabic: "لَا يُفَتَّرُ عَنْهُمْ وَهُمْ فِيهِ مُبْلِسُونَ", transliteration: "La yufattaru AAanhum wahum feehi mublisoona", transliterationB: "Laa yufattaru 'anhum wa hum feehi mublisoon", english: "Nowise will the (Punishment) be lightened for them, and in despair will they be there overwhelmed", romanUrdu: "Kabhi unke azaab mein kami na hogi, aur woh us mein mayous padey hongey" },
    { number: 76, arabic: "وَمَا ظَلَمْنَٰهُمْ وَلَٰكِن كَانُوا۟ هُمُ ٱلظَّٰلِمِينَ", transliteration: "Wama thalamnahum walakin kanoo humu alththalimeena", transliterationB: "Wa maa zalamnaahum wa laakin kaanoo humuz zaalimeen", english: "Nowise shall We be unjust to them: but it is they who have been unjust themselves", romanUrdu: "Unpar humne zulm nahin kiya balke woh khud hi apne upar zulm karte rahey" },
    { number: 77, arabic: "وَنَادَوْا۟ يَٰمَٰلِكُ لِيَقْضِ عَلَيْنَا رَبُّكَ ۖ قَالَ إِنَّكُم مَّٰكِثُونَ", transliteration: "Wanadaw ya maliku liyaqdi AAalayna rabbuka qala innakum makithoona", transliterationB: "Wa naadaw yaa Maaliku liyaqdi 'alainaa Rabbuka qaala innakum maakisson", english: "They will cry: \"O Malik! would that thy Lord put an end to us!\" He will say, \"Nay, but ye shall abide", romanUrdu: "Woh pukarenge, “aey maalik, tera Rubb hamara kaam hi tamam ka de to accha hai” woh jawab dega “tum yun hi padey rahogey" },
    { number: 78, arabic: "لَقَدْ جِئْنَٰكُم بِٱلْحَقِّ وَلَٰكِنَّ أَكْثَرَكُمْ لِلْحَقِّ كَٰرِهُونَ", transliteration: "Laqad jinakum bialhaqqi walakinna aktharakum lilhaqqi karihoona", transliterationB: "Laqad ji'naakum bilhaqqi wa laakinna aksarakum lilhaqqi kaarihoon", english: "Verily We have brought the Truth to you: but most of you have a hatred for Truth", romanUrdu: "Hum tumhare paas haqq lekar aaye thay magar tum mein se aksar ko haqq hi nagawaar tha”" },
    { number: 79, arabic: "أَمْ أَبْرَمُوٓا۟ أَمْرًۭا فَإِنَّا مُبْرِمُونَ", transliteration: "Am abramoo amran fainna mubrimoona", transliterationB: "Am abramooo amran fainnaa mubrimoon", english: "What! have they settled some plan (among themselves)? But it is We Who settle things", romanUrdu: "Kya in logon ne koi iqdam (plot) karne ka faisla karliya hai? Accha to hum bhi phir ek faisla kiye letey hain" },
    { number: 80, arabic: "أَمْ يَحْسَبُونَ أَنَّا لَا نَسْمَعُ سِرَّهُمْ وَنَجْوَىٰهُم ۚ بَلَىٰ وَرُسُلُنَا لَدَيْهِمْ يَكْتُبُونَ", transliteration: "Am yahsaboona anna la nasmaAAu sirrahum wanajwahum bala warusuluna ladayhim yaktuboona", transliterationB: "Am yahsaboona annaa laa nasma'u sirrahum wa najwaahum; balaa wa Rusulunaa ladaihim yaktuboon", english: "Or do they think that We hear not their secrets and their private counsels? Indeed (We do), and Our messengers are by them, to record", romanUrdu: "Kya inhon ne yeh samajh rakkha hai ke hum inki raaz ki baatein aur inki sargoshiyan sunte nahin hain? Hum sab kuch sun rahey hain aur hamare farishtey inke paas hi likh rahe hain" },
    { number: 81, arabic: "قُلْ إِن كَانَ لِلرَّحْمَٰنِ وَلَدٌۭ فَأَنَا۠ أَوَّلُ ٱلْعَٰبِدِينَ", transliteration: "Qul in kana lilrrahmani waladun faana awwalu alAAabideena", transliterationB: "Qul in kaana lir Rahmaani walad; fa-ana awwalul 'aabideen", english: "Say: \"If (Allah) Most Gracious had a son, I would be the first to worship", romanUrdu: "Inse kaho, agar waqai Rehman ki koi aulad hoti to sabse pehle Ibadat karne wala main hota”" },
    { number: 82, arabic: "سُبْحَٰنَ رَبِّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ رَبِّ ٱلْعَرْشِ عَمَّا يَصِفُونَ", transliteration: "Subhana rabbi alssamawati waalardi rabbi alAAarshi AAamma yasifoona", transliterationB: "Subhaana Rabbis samaawaati wal ardi Rabbil Arshi 'ammaa yasifoon", english: "Glory to the Lord of the heavens and the earth, the Lord of the Throne (of Authority)! (He is free) from the things they attribute (to him)", romanUrdu: "Paak hai aasmaano aur zameen ka farma rawan, Arsh ka maalik, un saari baaton se jo yeh log us ki taraf mansoob karte hain" },
    { number: 83, arabic: "فَذَرْهُمْ يَخُوضُوا۟ وَيَلْعَبُوا۟ حَتَّىٰ يُلَٰقُوا۟ يَوْمَهُمُ ٱلَّذِى يُوعَدُونَ", transliteration: "Fatharhum yakhoodoo wayalAAaboo hatta yulaqoo yawmahumu allathee yooAAadoona", transliterationB: "Fazarhum yakhoodoo wa yal'aboo hattaa yulaaqoo Yawmahumul lazee yoo'adoon", english: "So leave them to babble and play (with vanities) until they meet that Day of theirs, which they have been promised", romanUrdu: "Accha, inhein apne baatil khayalat mein garq aur apne khel mein munhamik rehne do, yahan tak ke yeh apna woh din dekh lein jiska inhein khauff dilaya jaa raha hai" },
    { number: 84, arabic: "وَهُوَ ٱلَّذِى فِى ٱلسَّمَآءِ إِلَٰهٌۭ وَفِى ٱلْأَرْضِ إِلَٰهٌۭ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْعَلِيمُ", transliteration: "Wahuwa allathee fee alssamai ilahun wafee alardi ilahun wahuwa alhakeemu alAAaleemu", transliterationB: "Wa Huwal lazee fissamaaa'i Ilaahunw wa fil ardi Ilaah; wa Huwal Hakeemul'Aleem", english: "It is He Who is Allah in heaven and Allah on earth; and He is full of Wisdom and Knowledge", romanUrdu: "Wahi ek aasman mein bhi khuda hai aur zameen mein bhi khuda, aur wahi hakeem o Aleem hai" },
    { number: 85, arabic: "وَتَبَارَكَ ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا وَعِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Watabaraka allathee lahu mulku alssamawati waalardi wama baynahuma waAAindahu AAilmu alssaAAati wailayhi turjaAAoona", transliterationB: "Wa tabaarakal lazee lahoo mulkus samaawaati wal ardi wa maa bainahumaa wa 'indahoo 'ilmus Saa'ati wa ilaihi turja'oon", english: "And blessed is He to Whom belongs the dominion of the heavens and the earth, and all between them: with Him is the Knowledge of the Hour (of Judgment): and to Him shall ye be brought back", romanUrdu: "Bahut baala-o-bartar hai woh jiske qabze mein zameen aur aasmaano aur har us cheez ki baadshahi hai jo zameen o aasman ke darmiyan payi jaati hai. Aur wahi qayamat ki ghadi ka ilm rakhta hai, aur usi ki taraf tum sab paltaye jaane waale ho" },
    { number: 86, arabic: "وَلَا يَمْلِكُ ٱلَّذِينَ يَدْعُونَ مِن دُونِهِ ٱلشَّفَٰعَةَ إِلَّا مَن شَهِدَ بِٱلْحَقِّ وَهُمْ يَعْلَمُونَ", transliteration: "Wala yamliku allatheena yadAAoona min doonihi alshshafaAAata illa man shahida bialhaqqi wahum yaAAlamoona", transliterationB: "Wa laa yamlikul lazeena yad'oona min doonihish shafaa'ata illaa man shahida bilhaqqi wa hum ya'lamoon", english: "And those whom they invoke besides Allah have no power of intercession;- only he who bears witness to the Truth, and they know (him)", romanUrdu: "Usko chodh kar yeh log jinhein pukarte hain woh kisi shafaat ka ikhtiyar nahin rakhte, illa yeh ke koi ilm ki bina par haqq ki shahadat de" },
    { number: 87, arabic: "وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَهُمْ لَيَقُولُنَّ ٱللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ", transliteration: "Walain saaltahum man khalaqahum layaqoolunna Allahu faanna yufakoona", transliterationB: "Wa la'in sa altahum man khalaqahum la yaqoolun nallaahu fa annaa yu'fakoon", english: "If thou ask them, who created them, they will certainly say, Allah: How then are they deluded away (from the Truth)", romanUrdu: "Aur agar tum insey pucho ke inhein kisne paida kiya hai to yeh khud kahenge ke Allah ne. Phir kahan se yeh dhoka kha rahe hain" },
    { number: 88, arabic: "وَقِيلِهِۦ يَٰرَبِّ إِنَّ هَٰٓؤُلَآءِ قَوْمٌۭ لَّا يُؤْمِنُونَ", transliteration: "Waqeelihi yarabbi inna haolai qawmun la yuminoona", transliterationB: "Wa qeelihee yaa Rabbi inna haa'ulaaa'i qawmul laa yu'minoon", english: "(Allah has knowledge) of the (Prophet's) cry, \"O my Lord! Truly these are people who will not believe", romanUrdu: "Kasam hai Rasool ke is qaul ki ke aey Rubb, yeh woh log hain jo maan kar nahin detay" },
    { number: 89, arabic: "فَٱصْفَحْ عَنْهُمْ وَقُلْ سَلَٰمٌۭ ۚ فَسَوْفَ يَعْلَمُونَ", transliteration: "Faisfah AAanhum waqul salamun fasawfa yaAAlamoona", transliterationB: "Fasfah 'anhum wa qul salaam; fasawfa ya'lamoon", english: "But turn away from them, and say \"Peace!\" But soon shall they know", romanUrdu: "Accha, aey nabi insey darguzar karo aur kehdo ke salaam hai tumhein, anqareeb inhein maaloom ho jayega" }
  ]
};
